  1→import React, { useState, useEffect } from 'react';
  2→import { createPortal } from 'react-dom';
  3→import { User } from '../types';
  4→import {
  5→  User as UserIcon, Mail, Key, Bell, LogOut, Fuel, Check, Copy, AlertTriangle,
  6→  Droplet, Database, CreditCard, ShieldCheck, LayoutList, History, FileText,
  7→  Download, Loader2, Sparkles, FolderOpen, TrendingUp, Zap, ArrowUpRight,
  8→  Palette, Eye, Globe, Lock
  9→} from 'lucide-react';
 10→import jsPDF from 'jspdf';
 11→import PageHeader from '../components/layout/PageHeader';
 12→import StripeCheckout from '../components/StripeCheckout';
 13→
 14→interface AccountProps {
 15→  user: User | null;
 16→  onLogout: () => void;
 17→  onNavigate: (view: any) => void;
 18→  onUpgrade: (plan: 'free' | 'pro' | 'enterprise') => void;
 19→  projectCount: number;
 20→  maxProjects: number;
 21→  initialTab?: 'profile' | 'subscription' | 'billing' | 'whitelabel';
 22→}
 23→
 24→const Account: React.FC<AccountProps> = ({ user, onLogout, onNavigate, onUpgrade, projectCount, maxProjects, initialTab = 'profile' }) => {
 25→  const [activeTab, setActiveTab] = useState<'profile' | 'subscription' | 'billing' | 'whitelabel'>(initialTab);
 26→  const [apiKeyCopied, setApiKeyCopied] = useState(false);
 27→  const [isProcessing, setIsProcessing] = useState(false);
 28→  const [upgradeModal, setUpgradeModal] = useState<{ planId: string; planName: string; newPrice: number } | null>(null);
 29→  const [paymentStep, setPaymentStep] = useState<'recap' | 'payment' | 'success'>('recap');
 30→  const [paidAmount, setPaidAmount] = useState(0);
 31→  const [paymentHistory, setPaymentHistory] = useState([
 32→    { id: 'INV-2024-003', date: '01/03/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
 33→    { id: 'INV-2024-002', date: '01/02/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
 34→    { id: 'INV-2024-001', date: '15/01/2024', amount: 49.00, desc: 'Pack GTO Gas (La Pompe)', status: 'Payé' },
 35→  ]);
 36→
 37→  // White Label state
 38→  const [whiteLabel, setWhiteLabel] = useState(() => {
 39→    try {
 40→      const saved = localStorage.getItem('citedby-whitelabel');
 41→      return saved ? JSON.parse(saved) : { logoUrl: '', agencyName: '', primaryColor: '#a855f7', secondaryColor: '#7c3aed' };
 42→    } catch { return { logoUrl: '', agencyName: '', primaryColor: '#a855f7', secondaryColor: '#7c3aed' }; }
 43→  });
 44→  const [wlSaved, setWlSaved] = useState(false);
 45→
 46→  const handleSaveWhiteLabel = () => {
 47→    localStorage.setItem('citedby-whitelabel', JSON.stringify(whiteLabel));
 48→    setWlSaved(true);
 49→    setTimeout(() => setWlSaved(false), 2000);
 50→  };
 51→
 52→  const generateBrandedPdf = () => {
 53→    const doc = new jsPDF();
 54→    doc.setFillColor(whiteLabel.primaryColor || '#a855f7');
 55→    doc.rect(0, 0, 210, 40, 'F');
 56→    doc.setTextColor(255, 255, 255);
 57→    doc.setFontSize(22);
 58→    doc.setFont('helvetica', 'bold');
 59→    doc.text(whiteLabel.agencyName || 'Mon Agence', 20, 25);
 60→    doc.setFontSize(10);
 61→    doc.text('Rapport AEO — Marque Blanche', 20, 33);
 62→    doc.setTextColor(60, 60, 60);
 63→    doc.setFontSize(12);
 64→    doc.text('Rapport de Visibilité IA', 20, 55);
 65→    doc.setFontSize(10);
 66→    doc.setFont('helvetica', 'normal');
 67→    doc.text(`Généré le ${new Date().toLocaleDateString('fr-FR')}`, 20, 63);
 68→    doc.text(`Client : ${user?.name || 'N/A'}`, 20, 70);
 69→    doc.setFontSize(14);
 70→    doc.setFont('helvetica', 'bold');
 71→    doc.text('Score Global AEO', 20, 90);
 72→    doc.setFontSize(36);
 73→    doc.setTextColor(whiteLabel.primaryColor || '#a855f7');
 74→    doc.text('78/100', 20, 110);
 75→    doc.setTextColor(100, 100, 100);
 76→    doc.setFontSize(9);
 77→    doc.text(`Powered by ${whiteLabel.agencyName || 'CitedBy.ai'}`, 20, 280);
 78→    doc.save(`Rapport_${whiteLabel.agencyName || 'AEO'}_${Date.now()}.pdf`);
 79→  };
 80→
 81→  useEffect(() => {
 82→    setActiveTab(initialTab);
 83→  }, [initialTab]);
 84→
 85→  useEffect(() => {
 86→    if (upgradeModal && paymentStep === 'success') { document.body.style.overflow = 'hidden'; }
 87→    return () => { document.body.style.overflow = ''; };
 88→  }, [upgradeModal, paymentStep]);
 89→
 90→  if (!user) return null;
 91→
 92→  // ── Helpers ──
 93→
 94→  const handleCopyApiKey = () => {
 95→    navigator.clipboard.writeText(`cb_pk_live_${user.id.substring(0, 8)}_${Math.random().toString(36).substr(2, 9)}`);
 96→    setApiKeyCopied(true);
 97→    setTimeout(() => setApiKeyCopied(false), 2000);
 98→  };
 99→
100→  const getPlanDetails = (plan: string) => {
101→    switch (plan) {
102→      case 'enterprise':
103→        return { name: 'Agency', marketingName: 'La Citerne', icon: <Database size={14} className="fill-current" />, style: 'bg-purple-500/10 text-purple-500 border-white/[0.1] shadow-[0_0_15px_rgba(168,85,247,0.1)]' };
104→      case 'pro':
105→        return { name: 'Pro', marketingName: 'La Pompe', icon: <Fuel size={14} className="fill-current" />, style: 'bg-purple-500/10 text-purple-400 border-primary/20 shadow-[0_0_15px_rgba(16,185,129,0.1)]' };
106→      default:
107→        return { name: 'Starter', marketingName: 'Le Jerrican', icon: <Droplet size={14} />, style: 'bg-white/[0.04] text-gray-300 border-white/[0.08]' };
108→    }
109→  };
110→
111→  const planDetails = getPlanDetails(user.plan);
112→  const projectPercentage = maxProjects >= 1000 ? 15 : Math.min((projectCount / maxProjects) * 100, 100);
113→  const isAtLimit = projectCount >= maxProjects && maxProjects < 1000;
114→
115→  // ── Pricing data ──
116→
117→  const plans = [
118→    {
119→      id: 'free', name: 'Starter', price: 29, period: '/mois',
120→      icon: <Droplet size={24} />, current: user.plan === 'free',
121→      features: ['1 Projet Actif / mois', 'Audit manuel', 'Support communauté'],
122→      cta: 'Plan Actuel',
123→    },
124→    {
125→      id: 'pro', name: 'Pro', price: 89, period: '/mois', popular: true,
126→      icon: <Fuel size={24} />, current: user.plan === 'pro',
127→      features: ['Indexation IA', '3 Projets Actifs / mois', 'Monitoring Continu', 'Support Prioritaire', 'API Access (Beta)', 'Rapports PDF marque blanche'],
128→      cta: 'Passer Pro',
129→    },
130→    {
131→      id: 'enterprise', name: 'Agency', price: 299, period: '/mois',
132→      icon: <Database size={24} />, current: user.plan === 'enterprise',
133→      features: ['Indexation IA', 'Projets illimités', 'Dedicated Account Manager', 'API Full Access', 'SSO & Sécurité avancée', 'Formation AEO équipe'],
134→      cta: 'Passer Agency',
135→    },
136→  ];
137→
138→  // Prix du plan actuel de l'utilisateur
139→  const currentPlanPrice = user.plan === 'enterprise' ? 299 : user.plan === 'pro' ? 89 : 29;
140→
141→  const handleUpgradeClick = (planId: string) => {
142→    const targetPlan = plans.find(p => p.id === planId);
143→    if (!targetPlan || targetPlan.current) return;
144→    setUpgradeModal({ planId, planName: targetPlan.name, newPrice: targetPlan.price });
145→    setPaymentStep('payment');
146→  };
147→
148→  const handleProcessPayment = () => {
149→    if (!upgradeModal) return;
150→    setIsProcessing(true);
151→    setTimeout(() => {
152→      const amountPaid = upgradeModal.newPrice - currentPlanPrice;
153→      const now = new Date();
154→      const dateStr = now.toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit', year: 'numeric' });
155→      const invoiceNum = `INV-${now.getFullYear()}-${String(paymentHistory.length + 1).padStart(3, '0')}`;
156→      const newInvoice = {
157→        id: invoiceNum,
158→        date: dateStr,
159→        amount: amountPaid,
160→        desc: `Upgrade ${planDetails.name} → ${upgradeModal.planName} (Prorata)`,
161→        status: 'Payé',
162→      };
163→      setPaymentHistory(prev => [newInvoice, ...prev]);
164→      setPaidAmount(amountPaid);
165→      onUpgrade(upgradeModal.planId as any);
166→      setIsProcessing(false);
167→      setPaymentStep('success');
168→    }, 2500);
169→  };
170→
171→  const handleCloseUpgradeModal = () => {
172→    setUpgradeModal(null);
173→    setPaymentStep('recap');
174→    setPaidAmount(0);
175→  };
176→
177→  // ── Invoice PDF ──
178→
179→  const generateInvoice = (payment: { id: string; date: string; amount: number; desc: string; status: string }) => {
180→    const doc = new jsPDF();
181→    doc.setFontSize(22);
182→    doc.setFont('helvetica', 'bold');
183→    doc.text('CitedBy.ai', 20, 20);
184→    doc.setFontSize(10);
185→    doc.setFont('helvetica', 'normal');
186→    doc.text(`Facture N° ${payment.id}`, 20, 30);
187→    doc.text(`Date : ${payment.date}`, 20, 35);
188→    doc.text('Facturé à :', 140, 30);
189→    doc.setFont('helvetica', 'bold');
190→    doc.text(user.name || 'Client', 140, 35);
191→    doc.setFont('helvetica', 'normal');
192→    doc.text(user.email || '', 140, 40);
193→    doc.line(20, 55, 190, 55);
194→    doc.setFont('helvetica', 'bold');
195→    doc.text('Description', 20, 62);
196→    doc.text('Montant HT', 160, 62);
197→    doc.line(20, 66, 190, 66);
198→    const priceHT = (payment.amount / 1.2).toFixed(2);
199→    const tva = (payment.amount - parseFloat(priceHT)).toFixed(2);
200→    doc.setFont('helvetica', 'normal');
201→    doc.text(payment.desc, 20, 75);
202→    doc.text(`${priceHT} €`, 160, 75);
203→    doc.line(20, 90, 190, 90);
204→    doc.text('Sous-total HT :', 130, 100);
205→    doc.text(`${priceHT} €`, 160, 100);
206→    doc.text('TVA (20%) :', 130, 107);
207→    doc.text(`${tva} €`, 160, 107);
208→    doc.setFont('helvetica', 'bold');
209→    doc.setFontSize(12);
210→    doc.text('Total TTC :', 130, 117);
211→    doc.text(`${payment.amount.toFixed(2)} €`, 160, 117);
212→    doc.setFontSize(8);
213→    doc.setFont('helvetica', 'italic');
214→    doc.text('Merci de votre confiance. Paiement effectué par CB.', 20, 140);
215→    doc.save(`Facture_${payment.id}.pdf`);
216→  };
217→
218→  // ── Render ──
219→
220→  return (
221→    <div className="animate-in fade-in duration-500">
222→      <PageHeader title="Mon compte" description="Gérez votre profil et vos préférences" />
223→
224→      {/* ── STEP 2 : PLEINE PAGE DE PAIEMENT (comme Recharge.tsx) ── */}
225→      {upgradeModal && paymentStep === 'payment' && (
226→        <div className="animate-in fade-in slide-in-from-right duration-500">
227→          <StripeCheckout
228→            mode="subscription"
229→            productName={`Plan ${upgradeModal.planName}`}
230→            productDescription={`Upgrade ${planDetails.name} → ${upgradeModal.planName}`}
231→            amount={upgradeModal.newPrice - currentPlanPrice}
232→            amountDetails={[
233→              { label: `Nouveau plan (${upgradeModal.planName})`, value: `${upgradeModal.newPrice.toFixed(2)} €` },
234→              { label: `Crédit plan ${planDetails.name}`, value: `- ${currentPlanPrice.toFixed(2)} €` },
235→              { label: 'À payer aujourd\'hui', value: `${(upgradeModal.newPrice - currentPlanPrice).toFixed(2)} €`, highlight: true, separator: true },
236→            ]}
237→            userEmail={user.email}
238→            onConfirm={handleProcessPayment}
239→            onBack={() => setPaymentStep('recap')}
240→            isProcessing={isProcessing}
241→          />
242→        </div>
243→      )}
244→
245→      {/* Contenu principal — masqué pendant le paiement */}
246→      {!(upgradeModal && paymentStep === 'payment') && (<>
247→
248→      {/* Header */}
249→      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
250→        <div className="flex items-center gap-4">
251→          <div className="w-14 h-14 bg-gradient-to-br from-purple-500 to-violet-600 rounded-2xl flex items-center justify-center text-white font-bold text-2xl shadow-lg shadow-purple-500/20 border-2 border-black">
252→            {user.name.charAt(0).toUpperCase()}
253→          </div>
254→          <div>
255→            <h1 className="text-3xl font-sans font-bold text-white">Compte & Plan</h1>
256→            <p className="text-gray-500 text-sm">Profil, abonnement, facturation</p>
257→          </div>
258→        </div>
259→        <button
260→          onClick={onLogout}
261→          className="flex items-center gap-2 px-4 py-2 bg-red-500/10 hover:bg-red-500/20 text-red-400 border border-red-500/20 rounded-full transition-colors text-sm font-medium"
262→        >
263→          <LogOut size={16} /> Déconnexion
264→        </button>
265→      </div>
266→
267→      {/* Tabs */}
268→      <div className="flex justify-center mb-10">
269→        <div className="inline-flex bg-white/[0.04] p-1.5 rounded-2xl border border-white/[0.08] flex-wrap justify-center gap-1">
270→          {([
271→            { key: 'profile', icon: UserIcon, label: 'Profil' },
272→            { key: 'subscription', icon: ShieldCheck, label: 'Abonnement & Projets' },
273→            { key: 'billing', icon: CreditCard, label: 'Facturation' },
274→            ...(user.plan === 'enterprise' ? [{ key: 'whitelabel' as const, icon: Palette, label: 'White Label' }] : []),
275→          ] as const).map(tab => (
276→            <button
277→              key={tab.key}
278→              onClick={() => setActiveTab(tab.key)}
279→              className={`px-5 py-2.5 rounded-2xl text-sm font-bold transition-all flex items-center gap-2 ${
280→                activeTab === tab.key
281→                  ? 'bg-gradient-to-r from-purple-500 to-violet-600 text-white shadow-lg'
282→                  : 'text-gray-500 hover:text-white'
283→              }`}
284→            >
285→              <tab.icon size={16} /> {tab.label}
286→            </button>
287→          ))}
288→        </div>
289→      </div>
290→
291→      {/* ═══════════════════════════════════════════════
292→          TAB 1 : PROFIL
293→          ═══════════════════════════════════════════════ */}
294→      {activeTab === 'profile' && (
295→        <div className="animate-in fade-in duration-300 grid lg:grid-cols-3 gap-8">
296→
297→          {/* Left: Profile Card + GTO Balance */}
298→          <div className="space-y-6">
299→            {/* Profile summary */}
300→            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] text-center relative overflow-hidden">
301→              <div className="absolute top-0 left-0 w-full h-24 bg-gradient-to-b from-white/5 to-transparent"></div>
302→              <div className="relative">
303→                <div className="w-24 h-24 mx-auto bg-gradient-to-br from-purple-500 to-violet-600 rounded-full flex items-center justify-center text-white font-bold text-4xl shadow-xl shadow-purple-500/20 mb-4 border-4 border-black">
304→                  {user.name.charAt(0).toUpperCase()}
305→                </div>
306→                <h2 className="text-xl font-bold text-white">{user.name}</h2>
307→                <p className="text-sm text-gray-500 mb-4">{user.email}</p>
308→                <div className={`inline-flex items-center gap-2 px-4 py-1.5 rounded-full border text-xs font-bold uppercase tracking-wide ${planDetails.style}`}>
309→                  {planDetails.icon}
310→                  {planDetails.marketingName}
311→                </div>
312→              </div>
313→            </div>
314→
315→            {/* GTO Gas balance */}
316→            <div className="ninja-card p-6 rounded-2xl border border-white/[0.08] relative overflow-hidden">
317→              <div className="flex justify-between items-start mb-4">
318→                <div className="p-3 bg-purple-500/10 rounded-2xl text-purple-400">
319→                  <Fuel size={24} />
320→                </div>
321→                <button
322→                  onClick={() => onNavigate('recharge')}
323→                  className="text-xs bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold px-3 py-1.5 rounded-full hover:brightness-110 transition-all"
324→                >
325→                  Recharger
326→                </button>
327→              </div>
328→              <p className="text-sm text-gray-500 mb-1">Solde GTO Gas</p>
329→              <div className="text-4xl font-bold text-white mb-2">{user.credits}</div>
330→              <div className="w-full bg-white/[0.08] h-1.5 rounded-full overflow-hidden">
331→                <div className="bg-purple-500 h-full rounded-full transition-all" style={{ width: `${Math.min((user.credits / 500) * 100, 100)}%` }}></div>
332→              </div>
333→              <p className="text-xs text-gray-500 mt-2">~{Math.floor(user.credits / 10)} audits restants</p>
334→            </div>
335→          </div>
336→
337→          {/* Right: Settings */}
338→          <div className="lg:col-span-2 space-y-8">
339→            {/* API Keys */}
340→            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08]">
341→              <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
342→                <Key size={20} className="text-purple-400" /> Clés API & Intégrations
343→              </h3>
344→              <div className="bg-black/40 border border-white/[0.08] rounded-2xl p-4 flex items-center justify-between gap-4">
345→                <div className="flex-1 overflow-hidden">
346→                  <p className="text-xs text-gray-500 mb-1 uppercase tracking-wider">Clé Publique</p>
347→                  <code className="text-sm text-purple-300 font-mono block truncate">cb_pk_live_{user.id.substring(0, 8)}...</code>
348→                </div>
349→                <button
350→                  onClick={handleCopyApiKey}
351→                  className="p-2 hover:bg-purple-500/10 rounded-full transition-colors text-gray-500 hover:text-white"
352→                  title="Copier la clé"
353→                >
354→                  {apiKeyCopied ? <Check size={18} className="text-purple-400" /> : <Copy size={18} />}
355→                </button>
356→              </div>
357→              <p className="text-xs text-gray-500 mt-3">
358→                Cette clé permet d'utiliser l'API CitedBy.ai. Ne la partagez jamais.
359→              </p>
360→              <button
361→                onClick={() => onNavigate('api-developer')}
362→                className="mt-4 text-sm text-purple-400 hover:text-purple-300 transition-colors flex items-center gap-1.5 font-medium"
363→              >
364→                <ArrowUpRight size={14} /> Documentation API complète
365→              </button>
366→            </div>
367→
368→            {/* Personal Info */}
369→            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08]">
370→              <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
371→                <UserIcon size={20} className="text-blue-400" /> Informations Personnelles
372→              </h3>
373→              <div className="grid md:grid-cols-2 gap-6">
374→                <div className="space-y-2">
375→                  <label className="text-sm font-medium text-gray-500">Nom Complet</label>
376→                  <input type="text" defaultValue={user.name} className="w-full bg-white/[0.04] border border-white/[0.08] rounded-xl px-4 py-2.5 text-white focus:border-purple-500/50 outline-none" />
377→                </div>
378→                <div className="space-y-2">
379→                  <label className="text-sm font-medium text-gray-500">Email</label>
380→                  <input type="email" defaultValue={user.email} disabled className="w-full bg-white/[0.04] border border-white/[0.08] rounded-xl px-4 py-2.5 text-gray-500 cursor-not-allowed" />
381→                </div>
382→                <div className="space-y-2 md:col-span-2">
383→                  <label className="text-sm font-medium text-gray-500">Workspace / Entreprise</label>
384→                  <input type="text" defaultValue="Mon Espace Personnel" className="w-full bg-white/[0.04] border border-white/[0.08] rounded-xl px-4 py-2.5 text-white focus:border-purple-500/50 outline-none" />
385→                </div>
386→              </div>
387→              <div className="mt-6 flex justify-end">
388→                <button className="btn-gradient px-6 py-2.5 text-white font-bold text-sm">Enregistrer les modifications</button>
389→              </div>
390→            </div>
391→
392→            {/* Notifications */}
393→            <div className="ninja-card p-8 rounded-2xl border border-white/[0.08]">
394→              <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
395→                <Bell size={20} className="text-purple-400" /> Préférences de notification
396→              </h3>
397→              <div className="space-y-4">
398→                {[
399→                  { label: "Rapport d'audit terminé", desc: 'Recevoir un email quand une analyse est finie.', default: true },
400→                  { label: 'Alerte de baisse de score', desc: 'Notification si le score AEO chute de plus de 10%.', default: true },
401→                  { label: 'Offres & Nouveautés', desc: 'Newsletters produit et mises à jour.', default: false },
402→                ].map((pref, i) => (
403→                  <div key={i} className="flex items-start justify-between pb-4 border-b border-white/[0.06] last:border-0 last:pb-0">
404→                    <div>
405→                      <p className="text-sm font-medium text-white">{pref.label}</p>
406→                      <p className="text-xs text-gray-500 mt-0.5">{pref.desc}</p>
407→                    </div>
408→                    <label className="relative inline-flex items-center cursor-pointer">
409→                      <input type="checkbox" defaultChecked={pref.default} className="sr-only peer" />
410→                      <div className="w-11 h-6 bg-gray-700 rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:start-[2px] after:bg-white after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-purple-500"></div>
411→                    </label>
412→                  </div>
413→                ))}
414→              </div>
415→            </div>
416→
417→            {/* Danger Zone */}
418→            <div className="border border-red-500/20 rounded-2xl p-6 bg-red-500/5">
419→              <h3 className="text-sm font-bold text-red-400 flex items-center gap-2 mb-2">
420→                <AlertTriangle size={16} /> Zone de danger
421→              </h3>
422→              <p className="text-xs text-gray-500 mb-4">La suppression du compte est irréversible. Toutes vos données seront perdues.</p>
423→              <button className="text-xs font-bold text-red-500 hover:text-red-400 border border-red-500/30 hover:bg-red-500/10 px-4 py-2 rounded-full transition-colors">
424→                Supprimer mon compte
425→              </button>
426→            </div>
427→          </div>
428→        </div>
429→      )}
430→
431→      {/* ═══════════════════════════════════════════════
432→          TAB 2 : ABONNEMENT & PROJETS
