 42→const Projects: React.FC<ProjectsProps> = ({ onBack, onNavigateToAnalysis, user, history, onViewAnalysis, projectCount, maxProjects, onNavigateToPlan, onDeductCredits, onSaveSolution, onNewAnalysis, onNavigateToRecharge, initialUrl, initialTab }) => {
 43→  // Navigation internal state: monitoring | report | action-plan | archives
 44→  const [activeTab, setActiveTab] = useState<'monitoring' | 'report' | 'action-plan' | 'archives'>(() => {
 45→    if (initialTab === 'archives') return 'archives';
 46→    if (initialTab === 'recommendations' || initialTab === 'action-plan') return 'action-plan';
 47→    if (initialTab === 'details' || initialTab === 'report') return 'report';
 48→    return 'monitoring';
 49→  });
 50→
 51→  useEffect(() => {
 52→    if (initialTab === 'archives') setActiveTab('archives');
 53→    else if (initialTab === 'recommendations') setActiveTab('action-plan');
 54→    else if (initialTab === 'details' || initialTab === 'report') setActiveTab('report');
 55→    else if (initialTab === 'overview') setActiveTab('monitoring');
 56→  }, [initialTab]);
 57→
 58→  // Use history to build project list, defaulting to mock if empty for demo
 59→  const projects = useMemo(() => {
 60→    if (history.length > 0) {
 61→      // Deduplicate by URL hostname, keeping the most recent
 62→      const uniqueMap = new Map<string, AnalysisResult>();
 63→      history.forEach(item => {
 64→        try {
 65→            const host = new URL(item.url).hostname;
 66→            if (!uniqueMap.has(host) || new Date(item.timestamp) > new Date(uniqueMap.get(host)!.timestamp)) {
 67→                uniqueMap.set(host, item);
 68→            }
 69→        } catch(e) {}
 70→      });
 71→      return Array.from(uniqueMap.values()).map((analysis, index) => mapAnalysisToProject(analysis, index));
 72→    } else {
 73→      // Mock data fallback if no history
 74→      return [
 75→        {
 76→          id: 'demo_1',
 77→          name: 'Exemple Site Demo',
 78→          domain: 'https://demo-site.com',
 79→          status: 'active',
 80→          lastRun: new Date().toISOString(),
 81→          visibilityScore: 45,
 82→          trend: 0,
 83→          nextRun: new Date(Date.now() + 86400000).toISOString()
 84→        }
 85→      ] as Project[];
 86→    }
 87→  }, [history]);
 88→
 89→  const [selectedProjectId, setSelectedProjectId] = useState<string>(() => {
 90→    if (initialUrl && projects.length > 0) {
 91→        try {
 92→            const targetHost = new URL(initialUrl).hostname;
 93→            // The projects mapping uses hostname as name
 94→            const found = projects.find(p => p.name === targetHost);
 95→            if (found) return found.id;
 96→        } catch(e) {}
 97→    }
 98→    return projects[0]?.id || '';
 99→  });
100→
101→  const [selectedAnalysisState, setSelectedAnalysisState] = useState<AnalysisResult | null>(null);
102→  
103→  // States for viewing archive modal
104→  const [isModalOpen, setIsModalOpen] = useState(false);
105→  const [currentSolution, setCurrentSolution] = useState<GeneratedSolution | null>(null);
106→
107→  const currentProject = projects.find(p => p.id === selectedProjectId) || projects[0];
108→  
109→  // Filter history for current project ONLY
110→  const projectHistory = useMemo(() => {
111→    return history
112→      .filter(h => {
113→          try { return new URL(h.url).hostname === currentProject.name; }
114→          catch(e) { return false; }
115→      })
116→      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
117→  }, [history, currentProject]);
118→
119→  // Reset selected analysis when project changes
120→  useEffect(() => {
121→    setSelectedAnalysisState(null);
